// 1. Partial: Bütün xüsusiyyətləri opsional edir
interface User {
  name: string;
  age: number;
}
type PartialUser = Partial<User>;
const user1: PartialUser = { name: "Alice" }; // age opsionaldır
console.log(user1); // Çıxış: { name: "Alice" }

// 2. Required: Bütün xüsusiyyətləri məcburi edir
type OptionalUser = { name?: string; age?: number };
type RequiredUser = Required<OptionalUser>;
const user2: RequiredUser = { name: "Bob", age: 25 }; // Hər ikisi məcburidir
// const user3: RequiredUser = { name: "Bob" }; // Səhv: age tələb olunur
console.log(user2); // Çıxış: { name: "Bob", age: 25 }

// 3. Readonly: Bütün xüsusiyyətləri yalnız oxuna bilən edir
type ReadonlyUser = Readonly<User>;
const user4: ReadonlyUser = { name: "Charlie", age: 30 };
// user4.name = "Dave"; // Səhv: name yalnız oxuna biləndir
console.log(user4); // Çıxış: { name: "Charlie", age: 30 }

// 4. Pick: Seçilmiş xüsusiyyətləri götürür
type UserName = Pick<User, "name">;
const user5: UserName = { name: "Eve" }; // Yalnız name tələb olunur
console.log(user5); // Çıxış: { name: "Eve" }

// 5. Omit: Seçilmiş xüsusiyyətləri çıxarır
type UserWithoutAge = Omit<User, "age">;
const user6: UserWithoutAge = { name: "Frank" }; // age yoxdur
console.log(user6); // Çıxış: { name: "Frank" }

// 6. Record: Yeni açar-dəyər cütləri yaradır
type Roles = "admin" | "user" | "guest";
type RolePermissions = Record<Roles, string[]>;
const permissions: RolePermissions = {
  admin: ["read", "write"],
  user: ["read"],
  guest: []
};
console.log(permissions); // Çıxış: { admin: ["read", "write"], user: ["read"], guest: [] }

// 7. ReturnType: Funksiyanın qaytarma tipini alır
type MyFunction = (a: number, b: string) => string;
type Return = ReturnType<MyFunction>;
const result: Return = "Hello"; // string tipi tələb olunur
console.log(result); // Çıxış: Hello

// 8. Parameters: Funksiyanın parametrlərinin tipini alır
type Params = Parameters<MyFunction>;
const params: Params = [42, "test"]; // [number, string] tələb olunur
console.log(params); // Çıxış: [42, "test"]

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}

// Partial ilə məhsul yeniləmə
type ProductUpdate = Partial<Product>;
function updateProduct(product: Product, updates: ProductUpdate): Product {
  return { ...product, ...updates };
}
const product: Product = { id: "P001", name: "Laptop", price: 999 };
const updated = updateProduct(product, { price: 1099 });
console.log(updated); // Çıxış: { id: "P001", name: "Laptop", price: 1099 }

// Pick ilə məhsulun yalnız adı və qiyməti
type ProductInfo = Pick<Product, "name" | "price">;
const productInfo: ProductInfo = { name: "Mouse", price: 25 };
console.log(productInfo); // Çıxış: { name: "Mouse", price: 25 }

// Record ilə kateqoriya inventarı
type Category = "electronics" | "clothing";
type Inventory = Record<Category, Product[]>;
const inventory: Inventory = {
  electronics: [{ id: "P001", name: "Laptop", price: 999 }],
  clothing: []
};
console.log(inventory); // Çıxış: { electronics: [{ id: "P001", name: "Laptop", price: 999 }], clothing: [] }

