// 1. Partial: Makes all properties optional
interface User {
  name: string;
  age: number;
}
type PartialUser = Partial<User>;
const user1: PartialUser = { name: "Alice" }; // age is optional
console.log(user1); // Output: { name: "Alice" }

// 2. Required: Makes all properties required
type OptionalUser = { name?: string; age?: number };
type RequiredUser = Required<OptionalUser>;
const user2: RequiredUser = { name: "Bob", age: 25 }; // Both are required
// const user3: RequiredUser = { name: "Bob" }; // Error: age is required
console.log(user2); // Output: { name: "Bob", age: 25 }

// 3. Readonly: Makes all properties read-only
type ReadonlyUser = Readonly<User>;
const user4: ReadonlyUser = { name: "Charlie", age: 30 };
// user4.name = "Dave"; // Error: name is read-only
console.log(user4); // Output: { name: "Charlie", age: 30 }

// 4. Pick: Selects specified properties
type UserName = Pick<User, "name">;
const user5: UserName = { name: "Eve" }; // Only name is required
console.log(user5); // Output: { name: "Eve" }

// 5. Omit: Excludes specified properties
type UserWithoutAge = Omit<User, "age">;
const user6: UserWithoutAge = { name: "Frank" }; // age is excluded
console.log(user6); // Output: { name: "Frank" }

// 6. Record: Creates key-value pairs
type Roles = "admin" | "user" | "guest";
type RolePermissions = Record<Roles, string[]>;
const permissions: RolePermissions = {
  admin: ["read", "write"],
  user: ["read"],
  guest: []
};
console.log(permissions); // Output: { admin: ["read", "write"], user: ["read"], guest: [] }

// 7. ReturnType: Gets the return type of a function
type MyFunction = (a: number, b: string) => string;
type Return = ReturnType<MyFunction>;
const result: Return = "Hello"; // string type is required
console.log(result); // Output: Hello

// 8. Parameters: Gets the parameter types of a function
type Params = Parameters<MyFunction>;
const params: Params = [42, "test"]; // [number, string] is required
console.log(params); // Output: [42, "test"]

